<template>
    <section>
        <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 searchpanel tablehead search float-left p-0">
            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 Search-panel float-left py-2 p-0">
                <div class="col-sm-12 col-md-12 col-lg-6 col-xl-6 float-left">
                    <div class="row mt-0">
                        <div class="col-6 col-sm-6 col-md-6 col-lg-6 col-xl-6 float-left pr-1 pl-0">
                            <div class="form-group">
                                <input type="search" v-model="contactsearch" v-on:keyup="SearchTextData($event)"
                                    class="form-control" :placeholder="$t('searchByNameOrEmail')" />
                            </div>
                        </div>
                        <div class="col-6 col-sm-6 col-md-6 col-lg-6 col-xl-6 float-left pl-0">
                            <div class="search-btm-btn background-0 text-left form-check-inline">
                                <a title="" v-on:click="Searchdata()" href="javascript:;" class="btn btn-success mr-1 px-4"
                                    data-toggle-tooltip="tooltip" data-original-title="Search"><em
                                        class="fa fa-search"></em></a>
                                <a href="javascript:;" title="" v-on:click="cancelOrRefresh()"
                                    class="btn btn-danger clearsearchtext px-4" data-toggle-tooltip="tooltip"
                                    data-original-title="Clear"><em class="fa fa-refresh"></em></a>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <loader :is-visible="isLoading"></loader>
        <tg-list :IsShowAction="true" :showCheckBox="false" ModuleName="CRM" SubModuleCode="CRM_ACCOUNTS"
            IdentityColumn="contact_id" :HeaderText="$t('Accounts')" :ListData="ContactsData"
            :HeaderButtons="listheaderbuttons" :HeaderData="ContactsHeader" :TotalRecords="TotalRecords"
            :IsSearchFieldsOnTop="false" :SearchPosition="top" :SearchFields="leftSearchFields"
            :RenderRowActionMethod="renderActions" :ListDataCallBackFunction="FetchData"
            :IsFilterApplied="searchCondition ? true : false" :SortExp="SortExp" :SortBy="SortBy"
            :NorecordfoundText="$t('NoRecordfound')" :CurrentPageNumber="PageNumber" v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
            v-on:SortdataButtonClick="sortdata">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'first_name'">
                    <a href="javascript:;" v-on:click="openContactModal(data.row.contact_id)">
                        {{ data.row.first_name }}
                    </a>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'IsPrimary'">
                    <div class="form-group text-center mb-0">
                        <label class="switch">
                            <input class="form-check-input custom-control-input dynamic" type="checkbox"
                                v-on:change="SetLoginOrPrimary(data.row, $event, 'IsPrimary')" v-model="data.row.IsPrimary"
                                v-bind:name="'IsLogin'">
                            <span class="slider round" style="cursor:default;">
                                <span class="slider-yes">Yes</span>
                                <span class="slider-no">No</span>
                            </span>
                        </label>
                    </div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'IsLogin'">
                    <div class="form-group text-center mb-0">
                        <label class="switch">
                            <input class="form-check-input custom-control-input dynamic" type="checkbox"
                                v-on:change="SetLoginOrPrimary(data.row, $event, 'IsLogin')" v-model="data.row.IsLogin"
                                v-bind:name="'IsLogin'">
                            <span class="slider round" style="cursor:default;">
                                <span class="slider-yes">Yes</span>
                                <span class="slider-no">No</span>
                            </span>
                        </label>
                    </div>
                </template>
            </template>
        </tg-list>
        <modalContactLogin v-if="IsContactLogin" v-bind:contactsdata="contactsLoginData" v-on:close="IsContactLogin = false"
            v-bind:contactsheader="contactsLoginHeader" v-bind:companyid="companyid">
        </modalContactLogin>
    </section>
</template>
  
<script>
import AccountDataService from "../../../services/DataService";
import modalContactLogin from "../Accounts/modalContactLogin.vue";
import Schema from "./AccountContactsSchema";
export default {
    components:
    {
        modalContactLogin
    },
    props: {
        contactsdata: {
            type: Array,
            required: true
        },
        contactsheader: {
            type: Array,
            required: true
        },
        sourceid: {
            type: String,
            required: true
        },
        submoduleCode: {
            type: String,
            required: true
        },
        companyid: {
            type: Number,
            required: true
        },
        modulename: {
            type: String,
            required: true
        }
    },
    data() {
        return {
            ContactsData: [],
            noRecordForTab: true,
            LeadStatus: '',
            ContactsHeader: [],
            IsPrimary: false,
            IsLogin: false,
            contactsearch: '',
            SelectedRow: 0,
            SearchLenght: 0,
            location: "",
            parentid: '',
            IsContactLogin: false,
            contactsLoginData: [],
            contactsLoginHeader: [],
            minwidth: {},
            AccType: '',
            isLoading: false,
            TotalRecords: 0,
            PageNumber: 1,
            PageSize: 10,
            SortBy: "",
            SortExp: "",
            CurrentPage: 1,
            TotalPages: 0,
            GroupStart: 1,
            GroupEnd: 3,
            Status: "",
            ModuleType: "",
            usertype: null,
            username: null,
            listActions: Schema.listActions,
            showAccountPopup: false,
            searchCondition: '',
            topsearchField: [
                {
                    fieldName: 'Search  ',
                    fieldType: "text",
                    fieldSearchConditionName: '',
                    isSearch: true,
                    value: "",
                    listOptions: []
                },
            ],
            HeadersData: [
                {
                    COLUMN_NAME: "first_name",
                    DATA_TYPE: "string",
                    DISPLAY_NAME: "Name",
                    DISPLAY_ORDER: 1,
                    IsEmailSent: "IsEmailSent",
                    SORTABLE: false,
                    VISIBLE: true
                },
                {
                    COLUMN_NAME: "RoleTitle",
                    DATA_TYPE: "string",
                    DISPLAY_NAME: "Role Title",
                    DISPLAY_ORDER: 2,
                    IsEmailSent: "IsEmailSent",
                    SORTABLE: false,
                    VISIBLE: true
                },
                {
                    COLUMN_NAME: "IsEmailSent",
                    DATA_TYPE: "string",
                    DISPLAY_NAME: "Is Email Sent",
                    DISPLAY_ORDER: 6,
                    IsEmailSent: "IsEmailSent",
                    SORTABLE: false,
                    VISIBLE: true
                },
                {
                    COLUMN_NAME: "IsPrimary",
                    DATA_TYPE: "string",
                    DISPLAY_NAME: "Is Primary",
                    DISPLAY_ORDER: 7,
                    IsEmailSent: "IsEmailSent",
                    SORTABLE: false,
                    VISIBLE: true
                },
                {
                    COLUMN_NAME: "IsLogin",
                    DATA_TYPE: "string",
                    DISPLAY_NAME: "Enable Login",
                    DISPLAY_ORDER: 8,
                    IsEmailSent: "IsEmailSent",
                    SORTABLE: false,
                    VISIBLE: true
                }
            ]
        };
    },
    watch: {
        contactsheader: function (value) {
            var vm = this;
            var objdata = [];
            $.each(value, function (index, item) {
                if (item.COLUMN_NAME !== 'first_name')
                    if (item.COLUMN_NAME !== 'last_name')
                        objdata.push(item);
            });
            this.ContactsHeader = JSON.parse(JSON.stringify(objdata));
            this.HeadersData.forEach((item) => {
                this.ContactsHeader.push(item);
            })
            this.ContactsHeader.forEach((item) => {
                if (item.COLUMN_NAME == 'first_name') {
                    item.DISPLAY_ORDER = 1;
                    item.SORTABLE = false;
                    item.settings = {
                        isInSlot: true,
                    };
                }
                if (item.COLUMN_NAME == 'RoleTitle') {
                    item.DISPLAY_ORDER = 2;
                    item.SORTABLE = false;
                }
                if (item.COLUMN_NAME == 'email_id') {
                    item.DISPLAY_ORDER = 3;
                    item.DISPLAY_NAME = 'Email Id';
                    item.SORTABLE = false;
                }
                if (item.COLUMN_NAME == 'business_phone') {
                    item.DISPLAY_ORDER = 4;
                    item.DISPLAY_NAME = 'Business Phone';
                    item.SORTABLE = false;
                }
                if (item.COLUMN_NAME == 'mobile_phone') {
                    item.DISPLAY_ORDER = 5;
                    item.DISPLAY_NAME = 'Mobile Phone';
                    item.SORTABLE = false;
                }
                if (item.COLUMN_NAME == 'home_phone') {
                    item.DISPLAY_ORDER = 6;
                    item.DISPLAY_NAME = 'Phone';
                    item.SORTABLE = false;
                }
                if (item.COLUMN_NAME == 'IsEmailSent') {
                    item.DISPLAY_ORDER = 7;
                    item.SORTABLE = false;
                }
                if (item.COLUMN_NAME == 'IsPrimary') {
                    item.DISPLAY_ORDER = 8;
                    item.SORTABLE = false;
                    item.settings = {
                        isInSlot: true,
                    };
                }
                if (item.COLUMN_NAME == 'IsLogin') {
                    item.DISPLAY_ORDER = 9;
                    item.SORTABLE = false;
                    item.settings = {
                        isInSlot: true,
                    };
                }
            })
            vm.ContactsHeader = this.ContactsHeader;
        },
        contactsdata: function (value) {
            var vm = this;
            const urlParams = new URLSearchParams(window.location.search);
            vm.parentid = urlParams.get('id');
            vm.AccType = urlParams.get('accountcode');
            if (vm.location != vm.$parent.location)
                vm.contactsearch = "";
            vm.location = vm.$parent.location;
            vm.ContactsData = value;
            $.each(value, function (index, item) {
                item.isDisable = false;
                if (item.IsPrimary == 1) {
                    item.isDisable = true;
                    vm.SelectedRow = item.contact_id;
                }
            });
            vm.ContactsData = JSON.parse(JSON.stringify(value));
            try {
                vm.LeadStatus = vm.$parent.LeadStatus;
            } catch (ex) { }
            vm.noRecordForTab = ((vm.ContactsData != null && vm.ContactsData.length > 0) ? false : true);
            setTimeout(function () { vm.ResponsiveDataTable('table-contacts-content') }, 500);
        }
    },
    created: async function () {
        var ths = this;
        ths.FetchData();
    },
    methods: {
        FetchData: function () {
            var vm = this;
            // vm.ContactsHeader = vm.ContactsHeader;
            // vm.ContactsData = vm.ContactsData
        },
        OpenContactLogin: function (item) {
            var vm = this;
            if ($.trim(item.email_id) == "") {
                vm.ShowAlert(vm.$t("Please fill email first."), "warning", true, vm.$t('Alert'));
                return false;
            }

            setTimeout(function () {
                vm.contactsLoginData = [];
                vm.contactsLoginHeader = [];
                var obj = [];
                obj.push(item)
                vm.contactsLoginData = obj;
                var obj1 = [];
                $.each(vm.contactsheader, function (ind, itm) {
                    if (itm.COLUMN_NAME == 'email_id')
                        obj1.push(itm);
                });
                vm.contactsLoginHeader = obj1;
                vm.IsContactLogin = true;
            }, 500);
        },
        SendClientMail: function (item) {
            var vm = this;
            if (item.IsLogin || item.USER_ID != null) {
                vm.isLoading = true;
                AccountDataService.SendActivationMail('userId=' + item.USER_ID).then(function (response) {
                    vm.isLoading = false;
                    if (response.data.status == 0) {
                        vm.ShowAlert(vm.$t('SuccessActivationMailToCL'), "success", true, vm.$t('Alert'));

                    }
                    else {
                        vm.ShowAlert(vm.$t('FailureActivationMailToCL'), "failure", true, vm.$t('Alert'));
                    }
                    vm.$parent.loadData(vm.location);
                })
            } else {
                vm.ShowAlert(vm.$t('NotAuthorizedActivation'), "warning", true, vm.$t('Alert'));
            }
        },
        deleteClient: function (item) {
            var vm = this;
            var data = {
                cid: item.contact_id,
                uid: (item.USER_ID == null ? 0 : item.USER_ID)
            };
            vm.confirmR(vm.$t("ConfirmDelete"), true, null, function (result) {
                var jsonData = JSON.stringify(data);
                AccountDataService.DeleteClient(jsonData).then(function (response) {
                    if (response.data.Status == "SUCCESS") {
                        vm.ShowAlert(vm.$t("Contact has been successfully deleted."), "success", true, vm.$t("Alert"));
                        vm.contactsearch = "";
                        vm.$parent.loadData(vm.location);
                    }
                });

            });
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach((actionItem) => {
                let action = { ...actionItem };
                switch (action.title) {
                    case "Active":
                        action.isVisible =
                            (self.isBlank(row.existing_client_id) ||
                                self.isBlank(row.project_id)) &&
                            (row.STATUS_ID == "1002" || row.STATUS_CODE == "NOT_VERIFIED");
                        break;
                    case "Inactive":
                        action.isVisible =
                            (self.isBlank(row.existing_client_id) ||
                                self.isBlank(row.project_id)) &&
                            (row.STATUS_ID == "1001" || row.STATUS_CODE == "NOT_VERIFIED");
                        break;
                    case "View":
                    case "Edit":
                        action.isVisible =
                            (self.isBlank(row.existing_client_id) ||
                                self.isBlank(row.project_id)) &&
                            row.status_id != "Closed" &&
                            row.status_id != "Cancelled";
                        break;
                    default:
                        action.isVisible = true;
                        break;

                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != "undefined") {
                this.searchCondition = value.searchCondition;
            } else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case "openContactModal":
                    this.openContactModal(item.contact_id);
                    break;
                case "SendClientMail":
                    this.SendClientMail(item);
                    break;
                case "deleteClient":
                    this.deleteClient(item);
                    break;
            }
        },
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            switch (s) {
                case 'CLIENT_NAME':
                    s = 'ACCOUNT_NAME'
                    break;
                case 'STATE':
                    s = 'TStat.name'
                    break;
            }
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                } else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                } else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }

            this.FetchData();
            $("#" + s).attr("class", SortDir);
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "openAddAccount":
                    this.showAccountPopup = true;
                    break;
                case "commonDeleteData":
                    this.commonDeleteData();
                    break;
                case "setTourGuideSteps":
                    this.setTourGuideSteps(0, this);
                    break;

            }
        },
        SaveAccount: function (item, hittype) {
            if (item.IsLogin || item.USER_ID != null || hittype == "direct") {
                var vm = this;
                if (item.RoleID == "0")
                    item.RoleID = null;
                var objectstring = JSON.stringify(item);
                vm.IsLogin = item.IsLogin;
                AccountDataService.SaveClientInfo(objectstring).then(function (response) {
                    if (response.data != "") {
                        if (response.data.msg == "SUCCESS") {
                            item.USER_ID = response.data.MAIN_ID
                            if (hittype != "direct")
                                vm.ShowAlert(vm.$t("User has been created successfully"), "success", true, vm.$t("Alert"));
                            if (vm.IsLogin) {
                            }
                        }
                        else if (response.data.msg == "UPDATE") {
                            if (hittype != "direct")
                                vm.ShowAlert(vm.$t("User has been updated successfully"), "success", true, vm.$t("Alert"));
                            vm.$parent.loadData(vm.location);
                        }
                        else if (response.data.msg == "EmailExist") {
                            if (hittype != "direct")
                                vm.ShowAlert(vm.$t("Email ID already exist. Please change the email ID"), "warning", true, vm.$t("Alert"));
                            vm.$parent.loadData(vm.location);

                        }
                        else {
                            if (hittype != "direct")
                                vm.ShowAlert(vm.$t('DeletedError', [vm.$t('User')]), "failure", true, vm.$t("Alert"));
                        }

                    }

                });

            }
            else {
                vm.ShowAlert(vm.$t("Please enable login."), "warning", true, vm.$t("Alert"));
            }
        },
        Searchdata: function () {
            var data = "";
            if ($.trim(this.contactsearch) != "") {
                this.SearchLenght = $.trim(this.contactsearch).length;
                data = " CONCAT(cont.first_name, ' ', cont.last_name,' ',cont.email_id) LIKE '%" + this.contactsearch + "%'";
            }
            this.$parent.loadData(this.location, encodeURIComponent(data).replace(/'/g, "%27"));
        },
        cancelOrRefresh: function () {
            this.contactsearch = "";
            this.$parent.loadData(this.location);
        },
        SearchTextData: function (event) {
            if (event.keyCode == 13) {
                this.Searchdata();
            }
        },
        SetLoginOrPrimary: function (itm, event, toggleType) {
            var vm = this;
            var IsPrimary = event.currentTarget.name.indexOf("IsPrimary");
            var message = "";
            var IsPrimaryVal = "";
            if (toggleType == 'IsPrimary') {
                IsPrimaryVal = itm.IsPrimary;
                message = "Are you sure you want to change primary?";
                talygen.confirm({
                    title: '',
                    message: message,
                    callback: function (result) {
                        if (result) {
                            $.each(vm.ContactsData, function (index, item) {
                                if (item.contact_id != itm.contact_id) {
                                    console.log("item", item);
                                    item.IsPrimary = false;
                                }
                            });
                            vm.SaveContactAsPrimary(itm, toggleType, IsPrimaryVal)
                        }
                        else {
                            itm.IsPrimary = !itm.IsPrimary;
                        }
                    }
                });
            } else {
                IsPrimaryVal = itm.IsLogin;
                if (itm.USER_ID != null) {
                    vm.SaveContactAsPrimary(itm, toggleType, IsPrimaryVal)
                } else {
                    vm.ShowAlert(vm.$t('NotAuthorizedEnabledLogin'), "warning", true, vm.$t('Alert'));
                    vm.$parent.loadData('contacts');
                    return false;
                }
            }
        },
        SaveContactAsPrimary: function (item, toggleType, IsPrimaryVal) {
            this.deleteContactFromTab
            var vm = this;
            var JsonObject = [];
            if (toggleType == 'IsPrimary') {
                JsonObject = {
                    contact_id: item.contact_id,
                    IsPrimary: IsPrimaryVal,
                    Type: 'Account',
                    refId: vm.sourceid,
                    ChangeType: toggleType
                }
            } else {
                JsonObject = {
                    contact_id: item.contact_id,
                    IsPrimary: IsPrimaryVal,
                    Type: 'Account',
                    refId: item.USER_ID,
                    ChangeType: toggleType
                }
            }
            var objectstring = JSON.stringify(JsonObject);
            vm.IsLogin = item.IsLogin;
            AccountDataService.SaveContactAsPrimary(objectstring).then(function (response) {

                if (response.data != "") {
                    if (response.data.msg == "SUCCESS") {
                        vm.ShowAlert(vm.$t("Contact Updated successfully."), "success", true, vm.$t("Alert"));
                        vm.$parent.loadData('contacts');
                    }
                }

            });
        },
        ChangeLeadOwner: function (id) {
            var varObj = this;
            varObj.$parent.OwnerIds.push(id);
            this.$parent.showLeadOwnerModal = (this.$parent.showLeadOwnerModal) ? false : true;
        },
        openContactModal: function (contactDetails) {
            var vm = this;
            var type = 'AddContact';
            if (contactDetails != null) {
                type = 'UpdateContact';
            }
            if ((typeof this.$parent.checkForAdditionalPermission !== 'undefined') && !this.$parent.checkForAdditionalPermission(type)) {
                alertR(vm.$t("additionalOwnerAuthorityWarning"), 'warning', true, vm.$t('Alert'));
            } else {
                this.$parent.iscontactDetails = contactDetails;
                this.$parent.showContactModal = (this.$parent.showContactModal) ? false : true;
            }
        },
        deleteContactFromTab: function (value) {
            var vm = this;
            if ((typeof this.$parent.checkForAdditionalPermission !== 'undefined') && !this.$parent.checkForAdditionalPermission('DeleteContact')) {
                alertR(vm.$t("additionalOwnerAuthorityWarning"), 'warning', true, vm.$t('Alert'));
            } else {
                var ths = this;
                var vm = checkVue;
                if (value > 0) {
                    vm.confirmR(vm.$t("ConfirmDeAssociateCommon") + vm.$t('Contact'), function (result) {
                        if (result) {
                            var postJSON = {
                                ids: value,
                                moduleName: ths.modulename,
                                subModuleCode: ths.submodulecode,
                                refCode: 'DELETE_VIEW_CONTACTS',
                                refId: ths.sourceid
                            };

                            var objectPostString = JSON.stringify(postJSON);
                            AccountDataService.CommonDelete(objectPostString).then(function (response) {
                                var box = "";
                                if (response.data[0].Status == "Success") {
                                    $('.chkItems:checkbox:checked').prop("checked", false).removeAttr('checked');
                                    vm.$parent.loadData('contacts');
                                    box = vm.ShowAlert(vm.$t('TeamDeassociateSuccess', [vm.$t('Contact')]), "success", true, vm.$t("Alert"));
                                }
                                else {
                                    box = vm.ShowAlert(vm.$t('ErrorDeassociateFailure', [vm.$t('Contact')]), "failure", true, vm.$t("Alert"));
                                }
                                setTimeout(function () {
                                    box.modal('hide');
                                }, 2000);

                            });
                        }
                    });
                }
                else {
                    vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Contact')]), "failure", true, vm.$t("Alert"));
                }
            }
        },
        bindStyle: function (item) {
            var styleObj = {};
            if (item == "personal_notes") {
                styleObj = {
                    'min-width': '200px',
                }
            }
            else {
                styleObj = {
                    'min-width': '120px',
                }
            }
            return styleObj;
        },
    },
};
</script>
<style scoped>
.action-list-box {
    opacity: 0;
    height: 0px;
    transition: opacity 1s;
}

.is-visible {
    display: inline-block;
    height: auto;
    overflow: hidden !important;
}
</style>